class Pairer:
    def __init__(self, strict=True):
        self.strict = strict

    def pair_up(self, a, b):
        pairs = []
        # BUG: loops over longer list but indexes shorter one
        longest = max(len(a), len(b))
        for i in range(longest):
            pairs.append((a[i], b[i]))
        return pairs


def pair_up(a, b):
    return Pairer().pair_up(a, b)


def main():
    names = ['alice', 'bob', 'carol']
    ages = [30, 25]
    out = pair_up(names, ages)
    print(out)


if __name__ == '__main__':
    main()
